import{_ as t,o as e,c as i,S as n}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"面试官问：监督学习、无监督学习、强化学习的区别？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_2-machine_learning.md","filePath":"面试官问/17ai/q_ai_2-machine_learning.md","lastUpdated":1778207238000}'),s={name:"面试官问/17ai/q_ai_2-machine_learning.md"};function r(l,a,d,o,p,h){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="面试官问-监督学习、无监督学习、强化学习的区别" tabindex="-1">面试官问：监督学习、无监督学习、强化学习的区别？ <a class="header-anchor" href="#面试官问-监督学习、无监督学习、强化学习的区别" aria-label="Permalink to &quot;面试官问：监督学习、无监督学习、强化学习的区别？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_2-machine_learning.html">机器学习</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_3-deep_learning.html">深度学习</a></p></blockquote><p><strong>考察点</strong>：三大机器学习范式的区分标准（数据是否有标签）、自监督学习与 LLM 训练的关系、RLHF 的本质理解</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p>机器学习三大范式，按&quot;数据是否有标签&quot;区分：</p><table><thead><tr><th>范式</th><th>数据特征</th><th>目标</th><th>典型算法</th></tr></thead><tbody><tr><td><strong>监督学习</strong></td><td>有标签 (x→y)</td><td>学习映射关系</td><td>线性回归、决策树、CNN</td></tr><tr><td><strong>无监督学习</strong></td><td>无标签</td><td>发现数据结构</td><td>K-Means、PCA、自编码器</td></tr><tr><td><strong>强化学习</strong></td><td>与环境交互</td><td>最大化累积奖励</td><td>Q-Learning、PPO</td></tr></tbody></table><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>监督学习：给学生「题目+答案」，考试考同类题</span></span>
<span class="line"><span>无监督学习：给学生「一堆题目」，自己找出题目的规律</span></span>
<span class="line"><span>强化学习：学生不知道答案，但做对了给糖，做错了惩罚，不断试错</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>关键延伸</strong>：</p><ul><li>半监督学习：少量标签 + 大量无标签数据</li><li>自监督学习：从数据自身生成标签（BERT 的 MLM、GPT 的 Next Token Prediction）—— 这是 LLM 训练的核心</li></ul><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>清晰区分三者的&quot;数据是否有标签&quot;</li><li>能说出 Transformer/LLM 使用自监督学习</li><li>RLHF（强化学习人类反馈）是 RL + 监督的组合</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_2-machine_learning.html">机器学习概念讲解</a></p></blockquote>`,5)])])}const m=t(s,[["render",r]]);export{u as __pageData,m as default};
